import { Element, Component, h, Prop, Listen, AttachInternals, Method } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';

@Component({
  tag: 'wdpr-chip-group',
  shadow: true,
  formAssociated: true,
})
export class WdprChipGroup {

  private _observer?: MutationObserver;
  private _chips: HTMLWdprChipElement[] = [];

  @Element() el!: HTMLWdprChipGroupElement;

  @Prop() selectMode: 'single' | 'multi' = 'multi';
  @Prop() layout: 'wrapped' | 'horizontal-scroll' = 'wrapped';
  @Prop() name?: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel?: string;

  @AttachInternals()
  internals!: ElementInternals;

  @Listen('wdprToggle')
  handleChipToggle(ev: CustomEvent<{ selected: boolean }>) {
    this._handleChipToggle(ev);
    this._syncChipsFromDom();
  }

  @Listen('formreset')
  handleFormReset() {
    this._updateFormValue();
  }

  @Method()
  async refreshInternals() {
    this._updateFormValue();
  }

  componentDidLoad() {
    this._initializeObserver();
    this._syncChipsFromDom();
  }

  disconnectedCallback() {
    this._observer?.disconnect();
  }

  private _syncChipsFromDom() {
    this._chips = Array.from(this.el.querySelectorAll('wdpr-chip'));
    // Assign mode prop to each chip
    this._chips.forEach(chip => {
      chip.mode = this.selectMode;
    });
    this._enforceSelectionRules();
    this._updateFormValue();
  }
  // Watch for selectMode changes and propagate to chips
  componentDidUpdate() {
    this._chips.forEach(chip => {
      chip.mode = this.selectMode;
    });
  }

  private get _selectedChips(): HTMLWdprChipElement[] {
    return this._chips.filter(chip => chip.selected);
  }

  private _initializeObserver() {
    this._observer = new MutationObserver(() => {
      this._syncChipsFromDom();
    });

    this._observer.observe(this.el, {
      childList: true,
      subtree: true,
    });
  }

  private _getFormValue(): string {
    return (this.selectMode === 'multi') ?
      String(this._chips.map(chip => chip.selected).join(', ')) :
      String(this._selectedChips[0]);
    ;
  }

  private _updateFormValue() {
    const shouldSubmit = this._chips.length > 0;

    if (!shouldSubmit) {
      this.internals?.setFormValue?.(this._getFormValue());

      return;
    }

    queueMicrotask(() => {
      if (this.internals && this.name) {
        this.internals?.setFormValue?.(this._getFormValue());
      }
    });
    this._updateValidity();
  }

  private _updateValidity() {
    this.internals?.setValidity?.({});
  }

  private _enforceSelectionRules() {
    if (this.selectMode === 'single') {
      this._selectedChips.slice(1).forEach(chip => chip.selected = false);
      if (this._selectedChips.length === 0 && this._chips.length > 0) {
        this._chips[0].selected = true;
      }
    }
  }

  private _handleChipToggle = (ev: CustomEvent<{ selected: boolean }>) => {
    if (this.selectMode === 'multi') return;

    const toggledChip = ev.target as HTMLWdprChipElement;

    if (!ev.detail.selected && this._selectedChips.length === 1 && this._selectedChips[0] === toggledChip) {
      toggledChip.selected = true;
      
      return;
    }

    this._chips.forEach(chip => {
      if (chip !== toggledChip) {
        chip.selected = false;
      }
    });
  };

  private get containerClass(): string {
    const layoutClasses = this.layout === 'horizontal-scroll' ? 'flex-nowrap w-max px-100' : 'flex-wrap';

    return customTwMerge(
      'flex gap-100 py-300',
      layoutClasses
    );
  }

  render() {
    const groupRole = this.selectMode === 'multi' ? 'group' : 'radiogroup';
    const ariaLabelValue = this.a11yLabel || this.name || 'Chip group';
    if (this.layout === 'horizontal-scroll') {
      return (
        <wdpr-scrollbar orientation="horizontal" class="w-full block">
          <div
            part="chip-group-container"
            class={this.containerClass}
            role={groupRole}
            aria-label={ariaLabelValue}
          >
            <slot />
          </div>
        </wdpr-scrollbar>
      );
    }

    return (
      <div
        part="chip-group-container"
        class={this.containerClass}
        role={groupRole}
        aria-label={ariaLabelValue}
      >
        <slot />
      </div>
    );
  }
}
